sql:
SELECT user_id, COUNT(*) AS comment_count
FROM poll_comments
GROUP BY user_id;

SELECT poll_title, poll_description, status, is_public, is_anonymous
FROM polls
WHERE poll_id = 1 AND is_deleted = 0;

SELECT plan_name, price
FROM plans
WHERE description LIKE '%Premium%' AND price <= (SELECT AVG(price) FROM plans);

SELECT plan_name, description
FROM plans
WHERE price < (SELECT AVG(price) FROM plans);

